// NOTE: this file will be generated by the Workflow CLI
import { handleWebhook } from '@vercel/workflow-core/runtime';

// NOTE: the second parameter provided to the Vercel Functions runtime
// contains `waitUntil`, and `cache`, but `handleWebhook` expects the
// request body to be passed as the second parameter, so wrap it in a
// function which ignores the second parameter.
async function handler(request: Request) {
  return await handleWebhook(request);
}

export const GET = handler;
export const POST = handler;
export const PUT = handler;
export const DELETE = handler;
export const PATCH = handler;
export const OPTIONS = handler;
export const HEAD = handler;
